with open('/Users/omeroth/CORPUS/index.html', 'r') as f:
    lines = f.readlines()

soc = '\u05e1\u05d5\u05e7\u05e8\u05d8\u05e1'
start = None
end = None
for i, line in enumerate(lines):
    if start is None and '{ id: 5, title:' in line and soc in line:
        start = i
    if start is not None and end is None and i > start:
        # End after the closing "    ]" + "  }," of the bonus week
        if line.strip() == '},' and '  },' in line:
            end = i + 1
            break

print(f"start={start}, end={end}")
print(f"Start line: {lines[start][:80].strip()!r}")
print(f"End line: {lines[end-1][:80].strip()!r}")

